VALUES
  ('aboriginal-f0899a01-moex-00397', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依憲法增修條文規定，有關總統、副總統之選舉與罷免，下列敘述何者錯誤？', '["總統、副總統由中華民國自由地區全體人民直接選舉之", "總統、副總統之罷免案，經立法院同意後提出，並經中華民國自由地區選舉人總額過半數之投票， 有效票過半數同意罷免時，即為通過", "總統、副總統候選人應聯名登記，在選票上同列一組圈選，以得票最多之一組為當選", "總統、副總統之罷免案，須經全體立法委員3分之1之提議，並經全體立法委員3分之2同意提出"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00398', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '關於政黨違憲解散案件之審理，下列敘述何者正確？', '["由司法院大法官組成憲法法庭審理之，並由參與案件審理之資深大法官擔任審判長", "政黨之目的或其行為，危害中華民國之存在或自由民主之憲政秩序者，由內政部聲請憲法法庭為宣 告政黨解散之判決", "宣告政黨解散之判決，其評決應經大法官現有總額2分之1以上同意；評決未達前項同意人數時， 應為不予解散之判決", "經憲法法庭宣告解散之政黨，其依政黨比例方式產生之立法委員，自憲法法庭判決生效日或主管機 關為解散公告日起之第3日，喪失其資格"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00399', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '有關釋憲聲請案之審理，下列敘述何者錯誤？', '["對學生所為之學習評量、其他管理、獎懲措施等措施，法院應尊重教師及學校本於專業及對事實真 象之熟知所為之決定，僅於其判斷或裁量違法或顯然不當時，得予撤銷或變更", "立法機關就各種社會給付之優先順序、規範目的、受益人範圍、給付方式及額度等項之有關規定， 自享有充分之形成自由，司法院大法官解釋對之向來採取較寬鬆之審查基準", "國家領土之範圍如何界定，純屬政治問題；其界定之行為，依權力分立之憲政原則，不受司法審查", "修改憲法亦係憲法上行為之一種，縱有重大明顯瑕疵，依權力分立之憲政原則，不受司法審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00400', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '財政與稅收自主為地方自治的內涵之一，從既有司法院大法官解釋之內涵觀之，下列敘述何者錯誤？', '["法律實施須由地方負擔經費時，因為法律之制定，無待地方參與，由立法院制定即可", "地方可以獨立管理並使用地方財產", "地方施政所需之經費負擔有法律保留原則之適用", "對地方負有協力義務之事項，中央依據法律可使地方分擔一定費用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00401', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '關於立法院職權之敘述，下列何者正確？', '["依憲法本文規定由監察院行使之人事同意權，依據憲法增修條文之規定，已改由立法院行使", "立法院對於各機關所編列預算之數額，得在款項目節間移動增減並追加或削減原預算之項目", "依據憲法本文之規定，立法院遇有立法委員五分之一以上之請求，得開臨時會", "依憲法增修條文之規定，立法院對總統之罷免案，須經全體立法委員至少二分之一以上之提議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00402', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族語言發展法的規定，非原住民族地區之鄉（鎮、市、區）公所當該區原住民人口達多少 人以上時，應置專職原住民族語言推廣人員？', '["1000人", "1500人", "2000人", "2500人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00403', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', 'Dongi 計畫召集部落族人成立原住民族照顧合作社，與縣政府簽訂特約，提供部落族人長期照顧 居家式服務，依據原住民族工作權保障法，Dongi所成立的合作社原住民社員要超過社員總數的百分 之幾？', '["百分之五十", "百分之六十", "百分之七十五", "百分之八十"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00404', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '為照顧原住民族長者，提供原住民族長者良好的高齡生活品質，原住民族委員會依據長期照顧十年計 畫2.0第6章原住民族長期照顧專章於原住民族地區及都會區廣設文化健康站，請問下列那一項非文 化健康站所提供的服務項目？', '["失智症照顧", "簡易健康照顧服務", "延緩老化失能活動", "營養餐飲服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00405', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '為協助原住民族社會發展，原住民族委員會設置原住民族綜合發展基金提供原住民經濟貸款，下列那 一項非可貸款的項目？', '["原住民購屋貸款", "原住民經濟貸款", "原住民青年創業貸款", "原住民微型經濟活動貸款"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00406', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-111-6ed013db', 'sub-aboriginal-f0899a01-07', NULL, 'single_choice', '依據原住民族教育法施行細則，在原住民族地區的原住民重點學校，其原住民學生人數應達學生總數 的多少以上？', '["四分之一", "三分之一", "二分之一", "三分之二"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "9fa39c7d6c92", "answer_pdf_sha1": "b77e59eedb08", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "607", "s": "0222", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
